diff --git a/llvm/lib/IR/ConstantRange.cpp b/llvm/lib/IR/ConstantRange.cpp
index d81a292916fd..bbf05362c4f1 100644
--- a/llvm/lib/IR/ConstantRange.cpp
+++ b/llvm/lib/IR/ConstantRange.cpp
@@ -1524,11 +1524,39 @@ ConstantRange ConstantRange::binaryAnd(const ConstantRange &Other) const {
   if (isEmptySet() || Other.isEmptySet())
     return getEmpty();

+  // Handle single-element cases precisely.
+  if (isSingleElement() && Other.isSingleElement())
+    return {*getSingleElement() & *Other.getSingleElement()};
+
   ConstantRange KnownBitsRange =
       fromKnownBits(toKnownBits() & Other.toKnownBits(), false);
-  ConstantRange UMinUMaxRange =
-      getNonEmpty(APInt::getZero(getBitWidth()),
-                  APIntOps::umin(Other.getUnsignedMax(), getUnsignedMax()) + 1);
+
+  // Compute a better lower bound for the AND result.
+  // The result can only be 0 if there's a value in this range that has no
+  // bits in common with Other. For the case where Other is a single value
+  // (mask), we can check if any zero-bit-only value falls in [min, max).
+  APInt Lower = APInt::getZero(getBitWidth());
+  if (Other.isSingleElement()) {
+    const APInt &Mask = *Other.getSingleElement();
+    APInt MinAndMask = getUnsignedMin() & Mask;
+    
+    // Find the maximum value that only has bits set where Mask has zeros.
+    // If this max is less than our minimum, then 0 is not reachable.
+    APInt MaxZeroBitVal = APInt::getZero(getBitWidth());
+    for (unsigned b = 0; b < getBitWidth(); b++) {
+      if (!Mask[b])
+        MaxZeroBitVal.setBit(b);
+    }
+    
+    // If the max zero-bit value is less than our min, no value in [min, max)
+    // can produce 0 when ANDed with Mask.
+    if (MaxZeroBitVal.ult(getUnsignedMin())) {
+      Lower = MinAndMask;
+    }
+  }
+
+  APInt Upper = APIntOps::umin(Other.getUnsignedMax(), getUnsignedMax()) + 1;
+  ConstantRange UMinUMaxRange = getNonEmpty(Lower, Upper);
   return KnownBitsRange.intersectWith(UMinUMaxRange);
 }

